// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IOpenDirective {
    function proposalOpen(uint256 amount, address policy, address owner, address token, string calldata url) external returns (uint256);
    function addFunds(address token, uint256 amount, address sender) external returns (bool);
    function proposalDeposit(uint256 assets, address receiver, uint256 proposal) external returns (uint256);
    function proposalMint(uint256 shares, address receiver, uint256 proposal) external returns (uint256);
    function proposalWithdraw(uint256 assets, address receiver, address owner, uint256 proposal) external returns (uint256);
    function proposalRedeem(uint256 shares, address receiver, address owner, uint256 proposal) external returns (uint256);
    function proposalCheck() external view returns (uint256);
    function closedProposal(uint256 proposal) external view returns (bool);
    function userDeposit(address user, uint256 proposal) external view returns(uint256);
    function userWithdrew(address user, uint256 proposal) external view returns(uint256);
    function userNumOfProposal(address user) external view returns(uint256);
    function userProposal(address user, uint256 proposal) external view returns(uint256);
    function proposalToken(uint256 proposal) external view returns(address);
    function getProposalWithdrawAmount(uint256 proposal) external view returns(uint256);
    function proposalReceiver(uint256 proposal) external view returns(address);
    function totalShares(uint256 proposal) external view returns(uint256);
    function whosOwner() external view returns (address);
    function getAuth(address user) external view returns (bool);
    function add(uint256 a, uint256 b) external pure returns(uint256);
    function newURL(string calldata url) external returns(bytes32);
    function checkURL(string calldata url) external view returns(bool);
}

contracts/OpenDirective.sol.content:
// SPDX-License-Identifier: MIT

pragma solidity ^0.8.20;
/// @title The Open Directive, Tokenized Reserve(ERC7425)
/// @author @jimstir

import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC4626.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./interfaces/IDirectiveToken.sol";

contract OpenDirective is ERC4626, ReentrancyGuard {
    using SafeERC20 for IERC20;

    /// @dev proposalOpen event
    event proposalO(
        address indexed token,
        uint256 indexed proposalNum,
        uint256 indexed amount,
        address recipient
    );
    /// dev proposlClose event
    event proposalC(
        uint256 indexed proposalNum,
        bool indexed closed,
        address closer
    );
    /// @dev deposit event
    event FundsAdded(
        address indexed token,
        uint256 indexed amount,
        uint256 indexed time,
        address sender
    );

    struct userAccount{
        uint256 proposal;
        uint256 deposit;
        uint256 withdrew;
    }

    struct proposalAccount{
        address owner;
        uint256 withdraw; // amount being withdrawn from treasury
        address receiver; // the receiving address/contract
        IERC20 token;
        uint256 time;
        uint256 deposits; // amount returned
        bytes32 urlHash; // the url for urlProposals
    }

    struct UserDeposit{
        uint256 num; // the deposit number
        uint256 amount;
        IERC20 token;
        address owner; // address of contract or wallet
        uint256 time; // time of deposit
        uint256 proposalNum;
    }

    address private _oOwner;
    //number of opened proposals
    uint256 private _proposalNum;
    uint256 private _depositNum;
    address private _agent;
    string private _name;
    IERC20 private _treasuryToken;

    mapping(address => bool) private _authUsers;
    mapping(uint256 => uint256) private _totalShares;
    mapping(uint256 => bool) private _closedProposals;

    //Track the number of proposals a shareholder has voted in
    mapping(address => mapping(uint256 => userAccount)) internal userBook;
    //mapping(uint256 => ownerAccount) internal ownerBook;
    mapping(uint256 => proposalAccount) internal proposalBook;
    // Record deposits for reference
    mapping(uint256 => UserDeposit) internal addFund;
    // For storing the urlList
    mapping(bytes32 => bool) internal urlList;
    // Find the proposalNumber of a url
    mapping(bytes32 => uint256) internal urlProposal;

    bool private _allowInternal = false;

    constructor(address agent, IERC20 tToken, string memory name, string memory symbol) ERC20(name, symbol) ERC4626(tToken){
        _oOwner = msg.sender;
        _treasuryToken = tToken; 
        _agent = agent;
    }

    // Get owner address
    function whosOwner() public view returns (address){
        return _oOwner;
    }
     // Get agent address
    function whosAgent() public view returns (address){
        return _agent;
    }

    /** @dev Check current total number of opened proposals
    * @return uint256
    */ 
    function proposalCheck() public view returns (uint256) {
        return _proposalNum;
    }

    // Authorized users of the treasury
    function getAuth(address user) public view returns (bool){
        return _authUsers[user];
    }

    /** @dev Amount deposited for shareToken by user, it is 1:1
    * - MUST be an ERC20 address
    * @param user address of user
    * @param proposal the proposal number for which the user deposited to
    */
    function userDeposit(address user, uint256 proposal) public view returns(uint256){
        return userBook[user][proposal].deposit;
    }

    /** @dev Amount withdrawn from given proposal by the user
    * @param user address of user
    * @param proposal number of the proposal the user withdrew
    */
    function userWithdrew(address user, uint256 proposal) public view returns(uint256){
        return userBook[user][proposal].withdrew;
    }

    /** @dev The total number of proposals joined by the user
    * @param user address of user
    */
    function userNumOfProposal(address user) public view returns(uint256){
        return userBook[user][0].proposal;
    }

    /** @dev The proposal number from the specific proposal joined by the user
    * @param user address of user
    * @param proposal the number the user was apart of
    * MUST NOT be zero
    */
    function userProposal(address user, uint256 proposal) public view returns(uint256){
        return userBook[user][proposal].proposal;
    }

    /** @dev Token used for given proposal
    * - MUST be ERC20 address
    * @param proposal number for requested token
    * @return token address
    */
    function proposalToken(uint256 proposal) external view returns(address){
        return address(proposalBook[proposal].token);
    }

    /** @dev Amount withdrawn for given proposal
    */
    function getProposalWithdrawAmount(uint256 proposal) external view returns(uint256){
        return proposalBook[proposal].withdraw;
    }

    /** @dev The receiver for given proposal
    */
    function proposalReceiver(uint256 proposal) external view returns(address){
        return proposalBook[proposal].receiver;
    }

    /** @dev Total shares issued for a given proposal
    * NOTE: Number does not change after proposal closed and shares are redeemed
    */
    function totalShares(uint256 proposal) public view returns(uint256){
        return _totalShares[proposal];
    }

    /** @dev Check if proposal is closed
    * @return true if closed
    */
    function closedProposal(uint256 proposal) public view returns(bool){
        return _closedProposals[proposal];
    }
    // Check if URL already has proposal
    function checkURL(string calldata url) external view returns (bool) {
        bytes32 hash = keccak256(abi.encodePacked(url));
        return urlList[hash];
    }
    /**
    * @dev SafeAdd function
    */
    function add(uint256 a, uint256 b) internal pure returns(uint256){
        return a + b;
    }
    // Update the agent address (only owner)
    function addAgent(address agent) external {
        require(msg.sender == _oOwner, "Only owner");
        _agent = agent;
    }
    // Add a new URL from an open proposal
    function newURL(string calldata url) public returns (bytes32) {
        bytes32 hash = keccak256(abi.encodePacked(url));
        urlList[hash] = true;
        return hash;
    }
    /** @dev Make a deposit to proposal creating new shares
    * - MUST be open proposal
    * - MUST NOT be a proposal that was previously closed
    * @param assets amount being deposited
    * @param receiver address of depositor, address receiving shares
    * @param proposal number of the proposal
    */
    function proposalDeposit(uint256 assets, address receiver, uint256 proposal) public nonReentrant returns (uint256) {
        require(proposalCheck() >= proposal, "Invalid proposal");

        _allowInternal = true;
        uint256 shares = super.deposit(assets, receiver);
        _allowInternal = false;
        _totalShares[proposal] = add(totalShares(proposal), shares);
        uint256 cc = userNumOfProposal(msg.sender) + 1;
        userBook[receiver][proposal].deposit = add(userDeposit(receiver, proposal), shares);
        userBook[msg.sender][0].proposal = cc;
        userBook[msg.sender][cc].proposal = proposal;
        return shares;
    }

    /** @dev Make a deposit to proposal creating new shares
    * - MUST have proposalNumber
    * NOTE: using the proposalMint() will cause shares to not be accounted for in a proposal
    * @param shares amount being deposited
    * @param receiver address of depositor
    * @param proposal the number to open proposal
    */
    function proposalMint(uint256 shares, address receiver, uint256 proposal) public nonReentrant returns(uint256){
         require(!closedProposal(proposal), "Proposal closed");
         require(proposalCheck() <= proposal, "Invalid proposal");

         _allowInternal = true;
         uint256 assets = super.mint(shares, receiver);
         _allowInternal = false;
         _totalShares[proposal] = add(totalShares(proposal), assets);
         uint256 cc = userNumOfProposal(msg.sender) + 1;
         userBook[receiver][proposal].deposit = add(userDeposit(receiver, proposal), assets);
         userBook[msg.sender][0].proposal = cc;
         userBook[msg.sender][cc].proposal = proposal;

         return assets;
    }

    /** @dev Burn shares, receive 1 to 1 value of assets
    * - MUST NOT have a userDeposit amount less than or equal to userWithdrew amount
    * @param assets amount of shares being returned
    * @param receiver address of depositor
    * @param owner the address to receive the treasury token
    * @param proposal the number to closed proposal
    */
    function proposalWithdraw(uint256 assets, address receiver, address owner, uint256 proposal)public nonReentrant returns(uint256){
        require(userWithdrew(receiver, proposal) + assets <= userDeposit(receiver, proposal), "Insufficient deposit");

        _allowInternal = true;
        uint256 shares = super.withdraw(assets, receiver, owner);
        _allowInternal = false;
        userBook[receiver][proposal].withdrew = add(userWithdrew(receiver, proposal), shares);

       return shares;
    }

    /** @dev Burn shares, receive 1 to 1 value of shares
    * - MUST have userDeposit less than or equal to userWithdrawal
    * NOTE: using ERC 4626 redeem() will not account for proposalWithdrawal
    */
    function proposalRedeem(uint256 shares, address receiver, address owner, uint256 proposal) public nonReentrant returns(uint256){
        require(userWithdrew(receiver, proposal) <= userDeposit(receiver, proposal), "Invalid redeem state");

        _allowInternal = true;
        uint256 assets = super.redeem(shares, receiver, owner);
        _allowInternal = false;
        userBook[receiver][proposal].withdrew = add(userWithdrew(receiver, proposal), assets);

        return assets;
    }
    /** @dev Issue new proposal
    * - MUST create new proposal number
    * - MUST account for amount to be withdrawn 
    * @param amount token amount being withdrawn
    * @param policy MAY be the policy address for urlProposals or address for TransferProposals
    * @param owner address of proposalOwner
    * @param url the address of the url for urlProposals 
    */
    function proposalOpen(uint256 amount, address policy, address owner, IERC20 token, string calldata url) external returns (uint256){
        require(msg.sender == _agent || msg.sender == _oOwner, "Not authorized");
        bytes32 hash = newURL(url);
        require(!urlList[hash]);

        uint256 num = proposalCheck() + 1;
        urlProposal[hash] = num;
        urlList[hash] = true;
        proposalBook[num].owner = owner;
        proposalBook[num].token = token;
        proposalBook[num].withdraw = amount;
        proposalBook[num].receiver = policy;
        _proposalNum = num;

        emit proposalO(address(token), num, amount, policy);
        return num;
    }
    /** @dev Account for added funds
    * - 
    * -  
    */
   function addFunds(IERC20 token, uint256 amount, address sender) public returns(bool){
        require(amount > 0, "Amount must be greater than zero");
        UserDeposit storage deposits = addFund[_depositNum];
        _depositNum = _depositNum + 1;

        deposits.num = _depositNum;
        deposits.amount = amount;
        deposits.token = token;
        deposits.time = block.timestamp;
        deposits.owner = sender;

        SafeERC20.safeTransferFrom(token, sender, address(this), amount);
        emit FundsAdded(address(token), amount, block.timestamp, sender);
        return true;
   }

    function deposit(uint256 assets, address receiver) public override nonReentrant returns (uint256) {
        return super.deposit(assets, receiver);
    }

    function mint(uint256 shares, address receiver) public override nonReentrant returns (uint256) {
        return super.mint(shares, receiver);
    }

    function redeem(uint256 shares, address receiver, address owner) public override nonReentrant returns (uint256) {
        require(_allowInternal, "Direct redeem not allowed, use proposalRedeem");
        return super.redeem(shares, receiver, owner);
    }

    function withdraw(uint256 assets, address receiver, address owner) public override nonReentrant returns (uint256) {
        require(_allowInternal, "Direct withdraw not allowed, use proposalWithdraw");
        return super.withdraw(assets, receiver, owner);
    }

}

contracts/SiteRecord.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./interfaces/IOpenDirective.sol";
import "./interfaces/IDirectiveToken.sol";

contract SiteRecord {
        event AnalystReportAdded(uint256 indexed analystNum, address indexed submitter, bytes32 data, uint256 timestamp);
        event ValidatorReportAdded(uint256 indexed reportNum, address indexed submitter, bytes32 data, uint256 amount, uint256 timestamp);
        event VerifierReportAdded(uint256 indexed submitNum, address indexed submitter, bytes32 data, bool update, bool approved, uint256 timestamp);
    // Report structure
    struct Report {
        bytes32 data; // Website address or CID hash
        address submitter;
        uint256 time; // time of report submission
        uint256 submitNum; // number of submission
    }

    uint256 private _currentAnalystNum; // The current analyst report number
    address private _owner; //the open directive owner
    address private _agent; //the agent address
    uint256 private _proposal; //the created proposal number on the Open Directive Tokenized Reserve
    address private _verifier; // verifer address??
    uint256 private _reportNum; // the current validator report number
    IOpenDirective private _direct;

    // analyst
    mapping(uint256 => Report) public analystReport;
    // validator submit number => analystReport number
    mapping(uint256 => mapping(uint256 => Report)) public validatorReport;
    // validator submit number => Report
    mapping(uint256 => Report) public verifierReport;
    mapping(uint256 => bool) private verifiedApproved;
    mapping(uint256 => bool) private verifiedUpdate;

    constructor(uint256 num, address owner, address agent, IOpenDirective direct){
        _owner = owner;
        _proposal = num;
        _agent = agent;
        _direct = direct;
    }

    modifier onlyOwners() {
        require(msg.sender == _owner || msg.sender == _agent, "Not authorized");
        _;
    }
    // Check if validator
    function checkValidator(address user) public view returns(bool){
        return _direct.userDeposit(user, _proposal) > 0;
    }
    // Get owner
    function getOwner() external view returns (address) {
        return _owner;
    }
    // Get verifier
    function getVerifier() external view returns (address) {
        return _verifier;
    }
    // Get anaylst report count
    function getAnalystReportNum() external view returns (uint256) {
        return _currentAnalystNum;
    }
    // Get the current analystReport
    function getAnalystReport() external view returns (bytes32, address, uint256){
        Report storage rep = analystReport[_currentAnalystNum];
        return (rep.data, rep.submitter, rep.time);
    }
    //  Get validator report count
    function getValidatorReportCount() external view returns (uint256) {
        return _reportNum;
    }
    // Get validator report hash
    function getValidatorReport(uint256 reportNum, uint256 analystNum) external view returns(bytes32, address, uint256){
        Report storage rep = validatorReport[reportNum][analystNum];
        return (rep.data, rep.submitter, rep.time);
    }

    // Get verifier report
    function getVerifierReport(uint256 submitNum) external view returns (bytes32, address, uint256) {
        Report storage r = verifierReport[submitNum];
        return (r.data, r.submitter, r.time);
    }
    // validator check verifier status, if approved and/or choosen for update
    function checkStatus(uint256 reportNum) external view returns(bool approved, bool update) {
        return (verifiedApproved[reportNum], verifiedUpdate[reportNum]);
    }
    //Add verifier address
    // ???
    function addVerifier(address user) external onlyOwners {
        _verifier = user;

    }
    // Add report by AI agent
    function addAnalystReport(string calldata data) external {
        require(msg.sender == _owner);

        bytes32 hash = keccak256(abi.encodePacked(data));
        _currentAnalystNum += 1;
        Report storage rep = analystReport[_currentAnalystNum];
        rep.data = hash;
        rep.submitter = msg.sender;
        rep.time = block.timestamp;
        emit AnalystReportAdded(_currentAnalystNum, msg.sender, hash, block.timestamp);

    }
    // Add report by validator
    function addValidatorReport(string calldata data, uint256 amount) external returns(uint256) {
        require(checkValidator(msg.sender));
        require(amount > 100);

        _reportNum += 1;
        bytes32 hash = keccak256(abi.encodePacked(data));
        Report storage rep = validatorReport[_reportNum][_currentAnalystNum];
        _direct.proposalDeposit(amount, msg.sender, _proposal);
        rep.data = hash;
        rep.submitter = msg.sender;
        rep.time = block.timestamp;
        emit ValidatorReportAdded(_reportNum, msg.sender, hash, amount, block.timestamp);
        return _reportNum;
    }
    /**  Add report by verifier agent
    * @param submitNum the current reportNum being verified
    */
    function addVerifierReport(string calldata data, uint256 submitNum, bool update, bool approved) external {
        require(msg.sender == _verifier);

        Report storage verify = verifierReport[submitNum];
        bytes32 hash = keccak256(abi.encodePacked(data));

        verify.data = hash;
        verify.submitter = msg.sender;
        verify.time = block.timestamp;
        verifiedApproved[submitNum] = approved;
        verifiedUpdate[submitNum] = update;
        emit VerifierReportAdded(submitNum, msg.sender, hash, update, approved, block.timestamp);
    }

}

contracts/Subscription.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./interfaces/IOpenDirective.sol";
import "./interfaces/IDirectiveToken.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

contract Subscription {
    using SafeERC20 for IERC20;

    event PriceSet(uint256 price);
    event Subscribed(address indexed user, uint256 months, uint256 amount);

    IERC20 private _token;
    uint256 private _monthlyPrice;
    address private _owner;
    uint256 private _proposal;

    struct UserSub {
        uint256 paidMonths;
        uint256 lastPaidTimestamp;
    }

    mapping(address => UserSub) public subscriptions;

    modifier onlyOwner() {
        require(msg.sender == _owner, "Only owner");
        _;
    }

    constructor(address tokenAddress, uint256 initialPrice, uint256 proposal) {
        _token = IERC20(tokenAddress);
        _monthlyPrice = initialPrice;
        _owner = msg.sender;
        _proposal = proposal;
    }
    //Get proposal number of OpenDirective policy
    function getProposal() external returns(uint256){
        return _proposal;
    }
    function getMonthsLeft(address user) external view returns (uint256) {
        UserSub storage sub = subscriptions[user];
        if (sub.paidMonths == 0) return 0;

        uint256 end = sub.lastPaidTimestamp + sub.paidMonths * 30 days;
        if (block.timestamp >= end) return 0;
        uint256 remaining = end - block.timestamp;
        return remaining / 30 days;
    }

    function setPrice(uint256 price) external onlyOwner returns(uint256){
        require(price > 0, "Price must be positive");
        _monthlyPrice = price;
        emit PriceSet(price);
        return _monthlyPrice;
    }

    function subscribe(uint256 amount) external {
        require(_monthlyPrice > 0, "Price not set");
        require(amount % _monthlyPrice == 0, "Amount must be multiple of monthly price");
        uint256 months = amount / _monthlyPrice;
        require(months > 0, "Must pay for at least one month");
        require(_token.balanceOf(msg.sender) >= amount, "Not enough funds");

        _token.safeTransferFrom(msg.sender, address(this), amount);

        UserSub storage sub = subscriptions[msg.sender];
        // If user has an active subscription, add months
        if (sub.paidMonths > 0 && block.timestamp < sub.lastPaidTimestamp + sub.paidMonths * 30 days) {
            uint256 remaining = (sub.lastPaidTimestamp + sub.paidMonths * 30 days) - block.timestamp;
            uint256 remainingMonths = remaining / 30 days;
            sub.paidMonths = remainingMonths + months;
            sub.lastPaidTimestamp = block.timestamp;
        } else {
            sub.paidMonths = months;
            sub.lastPaidTimestamp = block.timestamp;
        }
        emit Subscribed(msg.sender, months, amount);
    }


}

contracts/VerifierRewards.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

contract VerifierRewards {
    using SafeERC20 for IERC20;
    address private _verifier;
    address private _owner;
    uint256 private _maxReward;
    IERC20 private _token;

    struct RewardRecord {
        address recipient;
        uint256 amount;
        uint256 reportNum;
    }

    RewardRecord[] public rewards;

    event RewardSent(address indexed recipient, uint256 amount, uint256 reportNum);

    modifier onlyVerifier() {
        require(msg.sender == _verifier || msg.sender == _owner, "Only verifier or owner can send rewards");
        _;
    }

    constructor(address verifier, IERC20 token, address owner) {
        _verifier = verifier;
        _token = token;
        _owner = owner;
    }
    // get the number of rewards sent
    function getRewardCount() external view returns (uint256) {
        return rewards.length;
    }
    // Get the Reward Record
    function getRewardRecord(uint256 index) external view returns (address, uint256, uint256) {
        RewardRecord storage r = rewards[index];
        return (r.recipient, r.amount, r.reportNum);
    }
    // Get the total amount of tokens owned by rewards service
    function totalRewards()external view returns(uint256){
        return(_token.balanceOf(address(this)));
    }
    //set the max reward amount
    function setMax(uint256 max)external {
        require(msg.sender == _owner);
        _maxReward = max;
    }
    // Send rewards to validators
    function sendReward(address recipient, uint256 amount, uint256 reportNum) external onlyVerifier {
        require(_token.balanceOf(address(this)) >= 100, "Insufficient balance on contract");
        require(amount < _maxReward);
        require(recipient != address(0), "Invalid recipient");
        require(amount > 0, "Amount must be positive");

        _token.safeTransfer(recipient, amount);

        rewards.push(RewardRecord({recipient: recipient, amount: amount, reportNum: reportNum}));
        emit RewardSent(recipient, amount, reportNum);
    }

}

